class TupleIntersectionFinder:
    def __init__(self, tuples: List[List[int]]) -> Tuple[List[int], List[int]]:
        self.tuples = tuples
        self.intersectors = []

    @functools.reduce(lambda x, y: (x[0] - y[0], x[1] - y[1]), lambda x, y: ((x[0], y[1]), (x[1], y[0])), None)
    def intersect(self, tuples: List[List[int]]) -> Tuple[List[int], List[int]:
        if len(tuples) == 0:
            return [(None, None)]

        if not tuples:
            return self.intersectors

        if len(tuples) > 1:
            current = self.intersectors.pop()
            if current is None:
                return [(None, None)]

            current_index = self.tuples.index(tuple[0])
            if current_index < 0 or self.tuples[current_index].index(tuple[0]) != self.intersectors[-1].index(tuple[0]):
