import itertools

class RemoveLowercase:
    def __init__(self):
        self.result = []

    def remove_lowercase(self, string: str) -> str:
        current = self.result
        index = 0

        while True:
            if string[0].islower():
                current[index] = string[1]
                index += 1
            if string[0].isupper():
                current.pop(index)
            if string[1].islower():
                current[index] = string[2]
                index += 1
            if string[1].isupper():
                current.pop(index)
            if index == len(string):  # All characters processed
                break
            current = self.result
        return ''.join(current)

